input.command:
agent-browser --auto-connect errors && agent-browser --auto-connect eval "$(cat <<'EOF'
(function() {
  const points = Array.from(document.querySelectorAll('path.mark-symbol.role-graphics-symbol'));
  const threshold = 150;
  let steelblueCount = 0;
  let orangeCount = 0;
  let mismatchCount = 0;

  points.forEach(p => {
    const label = p.getAttribute('aria-label');
    if (!label) return;
    const hpMatch = label.match(/Horsepower: (\d+)/);
    if (!hpMatch) return;
    const hp = parseInt(hpMatch[1]);
    const fill = p.getAttribute('fill');

    if (hp < threshold) {
      if (fill === 'steelblue') steelblueCount++;
      else mismatchCount++;
    } else {
      if (fill === 'orange') orangeCount++;
      else mismatchCount++;
    }
  });

  return {
    totalPoints: points.length,
    steelblueCount,
    orangeCount,
    mismatchCount,
    threshold
  };
})()
EOF
)"

agent-browser --auto-connect eval "$(cat <<'EOF'
(function() {
  const points = Array.from(document.querySelectorAll('[aria-label*="Horsepower"]'));
  const threshold = 150;
  let steelblueCount = 0;
  let orangeCount = 0;
  let otherCount = 0;
  let belowThresholdSteelblue = 0;
  let belowThresholdOrange = 0;
  let aboveThresholdSteelblue = 0;
  let aboveThresholdOrange = 0;

  points.forEach(p => {
    const label = p.getAttribute('aria-label');
    const hpMatch = label.match(/Horsepower: ([\d.]+)/);
    if (!hpMatch) return;
    const hp = parseFloat(hpMatch[1]);
    const fill = p.getAttribute('fill') || window.getComputedStyle(p).fill;

    if (hp < threshold) {
      if (fill === 'steelblue' || fill === 'rgb(70, 130, 180)') belowThresholdSteelblue++;
      else if (fill === 'orange' || fill === 'rgb(255, 165, 0)') belowThresholdOrange++;
      else otherCount++;
    } else {
      if (fill === 'steelblue' || fill === 'rgb(70, 130, 180)') aboveThresholdSteelblue++;
      else if (fill === 'orange' || fill === 'rgb(255, 165, 0)') aboveThresholdOrange++;
      else otherCount++;
    }
  });

  return {
    threshold,
    belowThresholdSteelblue,
    belowThresholdOrange,
    aboveThresholdSteelblue,
    aboveThresholdOrange,
    otherCount
  };
})()
EOF
)"

